#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        char str[N][100005];
        for (int i = 0; i < N; i++) {
            scanf("%s", str[i]);
        }
        long long ans = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (i != j) {
                    int len = 0;
                    while (len < strlen(str[i]) && len < strlen(str[j]) && str[i][len] == str[j][len]) {
                        len++;
                    }
                    if (len > 0) {
                        if (strlen(str[i]) < strlen(str[j])) {
                            ans = (ans + 1) % MOD;
                        } else if (strlen(str[i]) > strlen(str[j])) {
                            ans = (ans + 1) % MOD;
                        }
                    }
                }
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

